                { id: 638, n: "Зачеканка отверстий в бетоне", w: 2, t: formatNorms(`Подготовительные мероприятия по удалению конусов, ПВХ трубок и заделке отверстий на всю толщину конструкции ремонтным составом`) },
                { id: 639, n: "Подготовленность поверхность основания перед нанесением", w: 2, t: formatNorms(`Качество поверхности (наплывы, выступы) не более 2 мм. Глубина раковины или каверны допускаются не более 5 мм следует удалить с поверхности бетона цементное молоко, грязь, жир, битумные и масляные пятна и прочие загрязнения`) },
                { id: 640, n: "Расшивка швов и заполнение штробы", w: 2, t: formatNorms(`В виде штрабы размером 30х30 мм и их заполнение специальным безусадочным ремонтным составом. расшивка швов и заполнению ремонтным составом штрабы`) },
                { id: 641, n: "Толщина слоя", w: 3, t: formatNorms(`Не менее 2 слоев. Нанесение второго слоя перпендикулярно первому, толщина одного слоя не менее 1 мм`) },
                { id: 642, n: "Соблюдение ТВР после нанесения", w: 2, t: formatNorms(`Последующие два дня температура воздуха и поверхности основания должна быть не ниже +5ºС и не выше +30ºС. В процессе твердения (не менее 24 часов) поверхность необходимо предохранять укрытием от воздействия дождя, длительного попадания прямых солнечных лучей и замораживания.`) }
